In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. You'll need to use `dup2()` to redirect the file descriptor. Here's a basic example:

```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int fd[2];  // Create a pipe
    pipe(fd);

    pid_t pid = fork();

    if (pid == -1) {
        // Error
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) {  // Child process
        close(fd[1]);  // Close write end in child
        dup2(fd[0], 0);  // Redirect stdin to read end
        close(fd[0]);  // Close read end

        execlp("command", "command", (char*)0);  // Replace child process with a new one

        // execlp() doesn't return on success, so any return here is an error
        std::cerr << "execlp failed" << std::endl;
        return 1;
    } else {  // Parent process
        close(fd[0]);  // Close read end in parent
        dup2(fd[1], 1);  // Redirect stdout to write end
        close(fd[1]);  // Close write end

        std::cout << "Output from child process:" << std::endl;
        std::system("command");  // Run command and capture its output

        wait(NULL);  // Wait for the child process to finish
    }

    return 0;
}
```

Replace `"command"` with the actual command you want to run. This example sets up a pipe, forks a child process, and redirects the child's standard input and output to the pipe. The parent process can then read the child's output or write to the child's input through the pipe.
